%[text] # 例4.0（画像のDFT）
%[text] 村松正吾　「多次元信号・画像処理の基礎と展開」
%[text] 動作確認： MATLAB R2025b
%[text] ## 準備
isVerbose = false;
prj = matlab.project.currentProject;
prjroot = prj.RootFolder;
datfolder = fullfile(prjroot,"data");
resfolder = fullfile(prjroot,"results");
myfilename = "example04_10"; % mfilename

imgname = "msipimg08";
imgfmt = "tiff";
%%
%[text] ## 画像データの読込
imgfile = fullfile(datfolder,imgname);
X = imresize(im2double(rgb2gray(imread(imgfile,imgfmt))),[96 96]);
%%
%[text] ## 原画像の表示
figure(1) %[output:770b8129]
imshow(X) %[output:770b8129]
title('原画像')  %[output:770b8129]
%%
%[text] ## 分布として表示
figure(2) %[output:1da1743a]
h = surf(X); %[output:1da1743a]
colormap("gray") %[output:1da1743a]
h.EdgeColor = "none"; %[output:1da1743a]

shading interp %[output:1da1743a]
daspect([8 8 1]) %[output:1da1743a]
ax = gca;
ax.FontSize = 18; %[output:1da1743a]
ax.YDir = 'reverse'; %[output:1da1743a]
ax.XTick = 0:20:100; %[output:1da1743a]
ax.YTick = 0:20:100; %[output:1da1743a]
ax.ZTick = 0:1; %[output:1da1743a]
ax.Color = 'none'; %[output:1da1743a]
fg = gcf;
fg.Color = 'none'; %[output:1da1743a]
set(fg,'Renderer','opengl');  %[output:1da1743a]
xlabel("$q_\mathrm{h}$","Interpreter","latex","FontSize",20); %[output:1da1743a]
ylabel("$q_\mathrm{v}$","Interpreter","latex","FontSize",20); %[output:1da1743a]
zlabel("$u(\mathbf{q})$","Interpreter","latex","FontSize",20); %[output:1da1743a]

exportgraphics(fg,fullfile(resfolder,"fig04-01a.png"),'BackgroundColor','none','ContentType','image') %[output:88018c91] %[output:1da1743a]
%%
%[text] ## 振幅スペクトルの表示
figure(3) %[output:2b263148]
Y = fftshift((abs(fft2(X,128,128))));
[Fx,Fy] = meshgrid(-1:2/128:1-2/128,-1:2/128:1-2/128);
h = surf(Fx,Fy,Y); %[output:2b263148]
A = 10*log10(h.CData);
h.CData = (A-min(A(:)))/(max(A(:))-min(A(:))); %[output:2b263148]
colormap("gray") %[output:2b263148]
h.EdgeColor = "none"; %[output:2b263148]

shading interp %[output:2b263148]
daspect([1 1 12000]) %[output:2b263148]
ax = gca;
ax.FontSize = 18; %[output:2b263148]
ax.YDir = 'reverse'; %[output:2b263148]
ax.XTick = -1:1; %[output:2b263148]
ax.XTickLabel = {"-\pi/\Delta_h","0","\pi/\Delta_h"}; %[output:2b263148]
ax.YTick = -1:1; %[output:2b263148]
ax.YTickLabel = {"-\pi/\Delta_v","0","\pi/\Delta_v"}; %[output:2b263148]
ax.ZTick = 0; %[output:2b263148]
ax.Color = 'none'; %[output:2b263148]
fg = gcf;
fg.Color = 'none'; %[output:2b263148]
set(fg,'Renderer','opengl');  %[output:2b263148]
xlabel("$\nu_\mathrm{h}$","Interpreter","latex","FontSize",20); %[output:2b263148]
ylabel("$\nu_\mathrm{v}$","Interpreter","latex","FontSize",20); %[output:2b263148]
zlabel("$|\tilde{u}(\mathbf{\nu})|$","Interpreter","latex","FontSize",20); %[output:2b263148]

exportgraphics(fg,fullfile(resfolder,"fig04-01b.png"),'BackgroundColor','none','ContentType','image') %[output:79874c1b] %[output:2b263148]
%%
%[text] ## 要素波形の表示
[Qx,Qy] = meshgrid(-0.5:1/128:0.5-1/128,-0.5:1/128:0.5-1/128);

idx = 1;
for iv = 0:2 %[output:group:02460b60]
    for ih = 0:2
        figure(3+idx) %[output:787053fc] %[output:30258d96] %[output:6adf6d17] %[output:48e917aa] %[output:173668c2] %[output:36c385c4] %[output:01dba393] %[output:254c4713] %[output:3c10b265]
        nuv = 2*pi*iv;
        nuh = 2*pi*ih;

        b = @(qv,qh) cos(nuv.*qv+nuh.*qh);

        h = surf(Qx,Qy,b(Qy,Qx)); %[output:787053fc] %[output:30258d96] %[output:6adf6d17] %[output:48e917aa] %[output:173668c2] %[output:36c385c4] %[output:01dba393] %[output:254c4713] %[output:3c10b265]
        axis off
        daspect([1 1 64])
        colormap("gray")
        h.EdgeColor = "none";
        shading interp
        idx = idx + 1;
        ax = gca;
        ax.Color = 'none';
        fg = gcf;
        fg.Color = 'none';
        set(fg,'Renderer','opengl');
        exportgraphics(fg,fullfile(resfolder,"fig04-01c"+"_"+num2str(iv)+"_"+num2str(ih)+".png"),'BackgroundColor','none','ContentType','image') %[output:5955949c] %[output:787053fc] %[output:05a8f023] %[output:30258d96] %[output:37ab5482] %[output:6adf6d17] %[output:6b8dd8c7] %[output:48e917aa] %[output:8d94eed4] %[output:173668c2] %[output:5d2d5261] %[output:36c385c4] %[output:49b7d463] %[output:01dba393] %[output:6330e7cd] %[output:254c4713] %[output:4be9fd5e] %[output:3c10b265]

    end
end %[output:group:02460b60]
